import {cn} from '@/lib/utils';

// Animation timing for the three streaming dots.
// These values exceed dds-duration-slower (500ms) by design: a 1.4s breathing pulse
// reads as "thinking" rather than "transitioning".
const STREAMING_DOT_DURATION = '1.4s';
const STREAMING_DOT_STAGGER_S = 0.2; // seconds per dot

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type AgentStreamingIndicatorProps = React.ComponentProps<'span'>;

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * Three animated dots indicating an agent is actively producing output.
 * Dots fade in sequence with a 1.4s total cycle and 0.2s per-dot stagger.
 *
 * @see §11 Agent Patterns — Streaming indicator in the Trident Visual Language spec
 *
 * @wcag 4.1.3 — uses role="status" so screen readers announce the live region
 */
function AgentStreamingIndicator({
  className,
  ...props
}: AgentStreamingIndicatorProps) {
  return (
    <span
      data-slot="streaming-indicator"
      role="status"
      aria-label="Agent is thinking"
      className={cn('inline-flex items-center gap-1', className)}
      {...props}
    >
      {[0, 1, 2].map(i => (
        <span
          key={i}
          data-slot="streaming-dot"
          aria-hidden="true"
          className="size-1.5 animate-pulse rounded-full bg-muted-foreground"
          style={{
            animationDelay: `${i * STREAMING_DOT_STAGGER_S}s`,
            animationDuration: STREAMING_DOT_DURATION,
          }}
        />
      ))}
    </span>
  );
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {AgentStreamingIndicator};
export type {AgentStreamingIndicatorProps};
